-- Migration 012e: Implementation Plans — Batch E (IDs 76-85)
-- ─────────────────────────────────────────────────────────────────────────────────────
BEGIN;

-- ── ID 76: PRASA Passenger Rail Recovery Programme ───────────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    76,
    'PRASA''s passenger rail network must be restored from ~100 million trips/year to a target of 400 million trips/year by 2030, reversing a decade of infrastructure decay, vandalism, and management dysfunction. The PRASA Recovery Plan (2023) allocates R124 billion over 10 years across rolling stock, signalling, and infrastructure rehabilitation. Operation Vulindlela identifies 10 priority corridors — led by Metrorail Cape Town (Central Line) and Soweto/Johannesburg — for accelerated investment and, where appropriate, private operations concessions with international rail operators such as Transdev and Keolis. Success requires parallel interventions on cable theft prevention, station safety, and a new PRASA board accountable for delivery milestones.',
    '[
      {"step":1,"title":"PRASA Board and Management Stabilisation","description":"Appoint a credible, transport-sector-experienced PRASA board and Group CEO with clear performance contracts tied to ridership recovery targets. Commission an independent operational audit of all 10 priority corridors to establish baseline asset condition, fare revenue potential, and security risk profiles. Publish audit findings within 90 days of board appointment.","timeline":"Q2–Q3 2025","responsible_party":"Department of Transport / Presidency (Operation Vulindlela)"},
      {"step":2,"title":"Cable Theft and Vandalism Mitigation Programme","description":"Deploy a dedicated rail corridor protection unit in partnership with SAPS and PRASA security on the Metrorail Cape Town Central Line and Johannesburg South corridors as the first phase. Introduce fibre-optic intrusion detection on rehabilitated track segments, and pilot community employment programmes along corridors to build local stake in infrastructure protection. Set 12-month target of 70% reduction in cable theft incidents on pilot corridors.","timeline":"Q3 2025–Q2 2026","responsible_party":"PRASA / SAPS / Department of Transport"},
      {"step":3,"title":"Rolling Stock Rehabilitation and New Fleet Delivery","description":"Accelerate delivery of the Gibela PRASA X''Trapolis Mega fleet (600 trains contracted) currently delayed beyond original 2020 schedule. Appoint an independent delivery monitor to track Gibela contract compliance. Rehabilitate existing Class 10M3 and 5M2A sets for short-term capacity on secondary corridors. Set milestone: 100 new train sets in service on priority corridors by end-2026.","timeline":"2025–2028","responsible_party":"PRASA / Gibela Rail Transport Consortium / DIMC"},
      {"step":4,"title":"Signal and Infrastructure Rehabilitation on Priority Corridors","description":"Implement corridor-by-corridor infrastructure rehabilitation starting with Cape Town Central Line Phase 2 (Langa–Khayelitsha), followed by Johannesburg Park Station–Naledi and Tshwane–Pretoria sections. Each corridor rehabilitation to follow a defined scope: trackwork, signalling, overhead traction equipment, and station upgrades. Establish a PRASA Infrastructure Programme Management Office (IPMO) reporting monthly to the Department of Transport.","timeline":"2025–2030 (phased by corridor)","responsible_party":"PRASA / IPMO / contracted civils and E&M contractors"},
      {"step":5,"title":"Private Operations Concessions for Non-Core Corridors","description":"Issue a request for proposals (RFP) for concession operators on 2–3 lower-priority Metrorail corridors where PRASA lacks operational capacity. Structure concessions as gross-cost contracts (operator paid per train-km, revenue risk retained by PRASA) in line with international best practice. Evaluate Transdev and Keolis proposals against transformation, skills transfer, and performance criteria under the PFMA and Preferential Procurement Regulations.","timeline":"RFP Q3 2025; concession agreements Q2 2026; operations commence Q4 2026","responsible_party":"PRASA / Department of Transport / National Treasury PPP Unit"},
      {"step":6,"title":"Fare Integration and Commuter Safety Programme","description":"Integrate PRASA Metrorail fares with bus and MyCiTi/BRT systems in Cape Town and Johannesburg using the Integrated Public Transport Network (IPTN) ticketing platform. Deploy CCTV, staffed security, and improved lighting at the 50 highest-risk stations. Introduce a passenger satisfaction survey published quarterly to drive accountability.","timeline":"Q1 2026–Q4 2027","responsible_party":"PRASA / City of Cape Town / City of Johannesburg / Department of Transport"},
      {"step":7,"title":"PRASA Recovery Milestone Review and Course Correction","description":"Conduct annual independent review of PRASA Recovery Plan progress against Operation Vulindlela corridor targets. Present findings to the Portfolio Committee on Transport. If ridership recovery targets are not met within 24 months, trigger a structured review of the concession model and consider expanding private operator scope.","timeline":"Annual (Q4 each year from 2026)","responsible_party":"Operation Vulindlela / Presidency / Department of Transport"}
    ]',
    '10 years (2024–2034); first measurable ridership recovery by 2027; full target of 400 million trips/year by 2030',
    'R124 billion over 10 years (PRASA Recovery Plan 2023); R11–14 billion per annum from national budget allocations and PRASA own revenue',
    'No new primary legislation required; PRASA operates under the Legal Succession to the South African Transport Services Act (No. 9 of 1989) as amended; concession agreements require compliance with PFMA Section 54 and National Treasury PPP Regulations; cable theft interventions require SAPS cooperation protocols under Criminal Procedure Act',
    'Concession agreements must be structured as PPPs under PFMA Treasury Regulation 16 to ensure compliance and value-for-money assessment. National Treasury PPP Unit must approve any transaction structure involving private operators receiving a government guarantee or subsidy. Draft concession framework should include measurable performance indicators (train punctuality, ridership, safety incidents) and step-in rights for PRASA if operator underperforms.',
    'High political salience — PRASA collapse affects the ANC''s core working-class constituency in Soweto, Khayelitsha, and Mitchell''s Plain. Operation Vulindlela provides a cross-departmental political mandate. The DA governs the Western Cape and Cape Town, creating a cooperative governance context for Metrorail Cape Town. Risk: union resistance (SATAWU) to private concessions; structured as gross-cost contracts (not privatisation) to manage labour relations.',
    'Netherlands: NS (Dutch Railways) gross-cost model with performance contracts and government subsidy managed by ProRail. UK: Directly Operated Railways (DOR) used as a fall-back operator when franchises fail — provides a model for PRASA retaining network control while contracting operations. Mozambique/Tanzania: Transdev currently operates rail services in Mozambique Ports and Railways under a management contract, demonstrating applicability in Southern African context.'
);

-- ── ID 77: Transport Economic Regulator — Operationalising the EROT Act ──────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    77,
    'The Economic Regulation of Transport Act (EROT Act, Act No. 6 of 2024) creates SA''s first unified independent transport economic regulator, covering ports, airports, rail, and pipelines — bringing these critical infrastructure sectors under a coherent regulatory regime for the first time. The regulator must be constituted, staffed, and operational within 36 months of the Act''s commencement date. Regulated entities include Transnet (freight rail and ports), ACSA (airports), and ATNS (air traffic). The regulator''s establishment is central to unlocking third-party access to the freight rail network and competitive port terminal operations, both of which are essential for economic growth targets under Operation Vulindlela.',
    '[
      {"step":1,"title":"Ministerial Proclamation and Commencement","description":"The Minister of Transport must gazette the commencement date of the EROT Act and issue the proclamation establishing the Transport Economic Regulator (TER) as a juristic person. Simultaneously, appoint an interim board of not more than five members with expertise in regulatory economics, transport, law, and finance to govern the entity during the establishment phase.","timeline":"Q2 2025","responsible_party":"Minister of Transport / Department of Transport"},
      {"step":2,"title":"Organisational Design and Staffing","description":"Develop an organisational structure for the TER based on a regulatory economics model. Priority appointments: CEO/Director-General, Chief Regulatory Officer (tariff methodology), Chief Legal Officer, and sector-specific heads for rail, ports, airports, and pipelines. Benchmark salary scales against NERSA, ICASA, and international comparators (Australian Competition and Consumer Commission, UK Office of Rail and Road) to attract qualified staff. Target: 80 core staff within 18 months.","timeline":"Q3 2025–Q4 2026","responsible_party":"Interim Board / Department of Transport / DPSA"},
      {"step":3,"title":"Tariff Methodology Development for Each Sector","description":"Publish draft tariff-setting methodologies for each regulated sector: (i) freight rail access pricing (cost-of-service plus reasonable return model); (ii) port terminal tariffs (price cap or revenue cap); (iii) airport charges (dual-till or single-till RAB model for ACSA); (iv) pipeline tariffs. Conduct public consultations with Transnet, ACSA, ATNS, private operators, shippers, and export councils. Finalise methodologies within 24 months of commencement.","timeline":"Q3 2025–Q2 2027","responsible_party":"TER / regulated entities / industry stakeholders"},
      {"step":4,"title":"Information Systems and Regulatory Accounts Framework","description":"Require Transnet, ACSA, and ATNS to submit disaggregated regulatory accounts separating infrastructure from operations, using a Regulatory Asset Base (RAB) methodology aligned with the EROT Act''s asset valuation provisions. Establish a TER data management system to receive, verify, and publish regulatory accounts annually. Appoint approved regulatory auditors for each entity.","timeline":"Q1 2026–Q4 2027","responsible_party":"TER / Transnet / ACSA / ATNS"},
      {"step":5,"title":"First Regulatory Period Price Determinations","description":"Issue first binding price determinations for freight rail access charges and port tariffs for a 5-year regulatory period beginning 2028. Determinations must be published in the Government Gazette with full methodology and reasoning. Any regulated entity or third-party operator may appeal to the Competition Tribunal on procedural grounds under the EROT Act appeal mechanism.","timeline":"Q1–Q4 2027","responsible_party":"TER Board"},
      {"step":6,"title":"Dispute Resolution and Enforcement Protocols","description":"Establish a formal dispute resolution mechanism for third-party access complaints: phased process of mediation (30 days), TER determination (60 days), and appeal to Competition Tribunal. Publish enforcement guidelines for access denials, discriminatory pricing, and cross-subsidisation abuses. Issue TER''s first annual State of Transport Regulation report to Parliament.","timeline":"Q2 2026–Q2 2027","responsible_party":"TER / Competition Tribunal / Department of Transport"}
    ]',
    '36 months for full operationalisation (2025–2027); first price determinations by 2028',
    'R250–350 million establishment cost (offices, IT systems, staff); ongoing annual budget R180–220 million funded through operator levies and appropriation during transition',
    'Economic Regulation of Transport Act No. 6 of 2024 (primary legislation — already enacted); EROT Regulations to be developed by the Minister of Transport under Section 87; sector-specific access rules for freight rail under Section 34 require separate gazetting; any amendments to Transnet Concessioning Act or ACSA Act to align with EROT regime',
    'Section 87 regulations are critical: they will define tariff methodology principles, dispute resolution procedures, and the RAB valuation approach. Early gazetting of draft regulations for public comment is essential to give regulated entities sufficient notice before first price determinations. Consider sequencing port and rail tariff reviews first (highest economic impact) before airports and pipelines.',
    'Strong support from Operation Vulindlela and the Presidency — the TER is listed as a priority reform. Transnet and ACSA have institutional interests in predictable regulatory outcomes and will cooperate if methodology is transparent. Risk: Transnet may resist disaggregated accounting requirements that expose cross-subsidies. ATNS and ACSA may lobby for generous RAB valuations. National Treasury supports the reform as it reduces fiscal risk from Transnet balance sheet.',
    'Australia: Australian Competition and Consumer Commission (ACCC) regulates rail access under the Competition and Consumer Act, with a National Access Regime. UK: Office of Rail and Road (ORR) sets Network Rail access charges through five-year control periods (CP5, CP6, CP7) using a RAB model — a close precedent for SA''s freight rail tariff methodology. New Zealand: Commerce Commission regulates airport charges (ACSA equivalent) using a price-quality path methodology.'
);

-- ── ID 78: Road Accident Fund Structural Reform ───────────────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    78,
    'The Road Accident Fund (RAF) carries a structural actuarial deficit of R450 billion — the largest contingent liability on the South African fiscal balance sheet outside of state pension obligations. The root cause is a fault-based compensation system that is exploited by personal injury attorneys who extract approximately R17 billion per year in legal fees, representing 40% of total claims cost. The RAF Amendment Bill (2023) proposes replacing this system with the Road Accident Benefit Scheme (RABS): a no-fault, capped-benefit model that provides faster, administratively determined payments for medical costs, loss of income, and rehabilitation, while eliminating general damages claims and the associated litigation economy. Implementation requires phased legislative transition, a new RABS administrative entity, and a multi-year debt resolution plan with National Treasury.',
    '[
      {"step":1,"title":"Parliamentary Passage of the RAF Amendment Bill / RABS Enabling Legislation","description":"Complete Parliamentary processing of the RAF Amendment Bill (introduced 2023, referred to Portfolio Committee on Transport). Engage the legal fraternity (Law Society of SA, Advocates for Transformation) on transition provisions and legal aid implications. Ensure the Constitutional Court challenge risk is mitigated by providing adequate transitional provisions for existing claims and legal practitioners whose livelihoods depend on the current system.","timeline":"Q2 2025–Q1 2026","responsible_party":"Department of Transport / Parliamentary Portfolio Committee on Transport"},
      {"step":2,"title":"Establish RABS Administrative Entity","description":"Constitute the RABS as a new juristic entity (or transformed RAF entity) with a board and CEO appointed by the Minister of Transport. Design the claims adjudication system: medical assessment panels, occupational therapist assessments for loss of income, and an internal review mechanism. Benchmark operational model against Workmen''s Compensation Fund (WCF/COID) and New Zealand Accident Compensation Corporation (ACC).","timeline":"Q2 2025–Q4 2026 (parallel to legislation)","responsible_party":"Department of Transport / National Treasury"},
      {"step":3,"title":"Actuarial Recalibration and Deficit Resolution Plan","description":"Commission an independent actuarial review of the RAF deficit under the new RABS benefit structure to determine the true long-run liability once general damages claims are eliminated. Develop a 15–20 year deficit amortisation plan with National Treasury, specifying the fuel levy allocation to RAF, any additional hypothecated revenue sources, and the annual budget appropriation required. Present plan to Cabinet and Parliament.","timeline":"Q3 2025–Q2 2026","responsible_party":"RAF / RABS / National Treasury / Government Actuary''s Department"},
      {"step":4,"title":"Rehabilitation and Medical Claims Processing System","description":"Develop an integrated claims management IT system for RABS covering: accident registration (linked to RTMC crash database), medical assessment workflow, rehabilitation provider network, and payment processing. Ensure system can process 200,000+ claims per year within statutory timeframes. Pilot the claims system with a cohort of claimants 12 months before the RABS commencement date.","timeline":"2026–2027","responsible_party":"RABS / SITA (State IT Agency)"},
      {"step":5,"title":"Transition Provisions: Manage Existing RAF Claim Backlog","description":"Develop a structured run-off plan for the 700,000+ existing RAF claims in the pipeline. Prioritise settlement of the oldest and highest-severity claims. Establish a cut-off date after which all new claims must proceed under RABS. Ring-fence the run-off fund from RABS operations and report separately on run-off liability annually.","timeline":"2026–2032 (run-off period)","responsible_party":"RAF / RABS / National Treasury"},
      {"step":6,"title":"Legal Practitioner Transition and Access to Justice","description":"Work with the Legal Aid SA and the Department of Justice to ensure that road accident victims who cannot navigate the RABS administrative system have access to legal assistance for the internal review and appeals process. Design the RABS internal review mechanism to be accessible without legal representation as the default. Publish benefit schedule clearly in all 11 official languages.","timeline":"2026–2027","responsible_party":"RABS / Legal Aid SA / Department of Justice"},
      {"step":7,"title":"Annual Actuarial and Financial Reporting","description":"Require RABS to publish an annual report including an actuarial valuation of the outstanding claims liability, a financial sustainability assessment, and a benefit adequacy review. Table report in Parliament and subject to Auditor-General audit. Set a target of reducing the structural deficit to below R200 billion (in real terms) within 10 years of RABS commencement.","timeline":"Annual from RABS commencement","responsible_party":"RABS / Auditor-General / Portfolio Committee on Transport"}
    ]',
    '3–4 years for legislation and RABS establishment (2025–2028); 15–20 years to amortise existing RAF deficit',
    'Administrative savings of R10–15 billion per year once general damages litigation is eliminated; RABS establishment costs R500 million–R1 billion (IT, staffing, premises); existing RAF deficit R450 billion requires long-term funding from fuel levy and appropriation',
    'Road Accident Fund Amendment Bill (2023) — primary legislation; may require a new Road Accident Benefit Scheme Act if Amendment Bill approach is abandoned; actuarial provisions may require changes to RAF Act (Act No. 56 of 1996); constitutional implications require legal opinion on right to access courts (Section 34 of Constitution)',
    'The constitutional dimension is the key legal risk: the general damages claim is a private right vested in road accident victims, and its elimination by statute could be challenged under Section 34 (access to courts) and Section 25 (property rights). Draft legislation should include a proportionality justification referencing the public interest in fiscal sustainability, the availability of administrative remedies, and the improved speed and certainty of RABS benefits. Taransition provisions must allow claimants with existing causes of action to elect the most favourable regime.',
    'Moderate political feasibility constrained by a well-organised legal industry lobby. Personal injury attorneys generate substantial fee income from the current system and have historically blocked RABS. The ANC government has attempted RABS reform since 2005 with limited success. The fiscal imperative is now stronger given the R450 billion deficit size. Post-2024 GNU context creates potential for reform if DA (which governs Transport Ministry) pushes through. Trade unions support RABS for its faster worker benefits for injured commuters.',
    'New Zealand: Accident Compensation Corporation (ACC) is the global benchmark — no-fault scheme covering all accidents (road, work, medical), funded through levies, with rapid administrative payments and strong rehabilitation focus. Australia: state-based CTP insurance schemes in Victoria (TAC) and New South Wales (iCare) moved to no-fault models in 2017–2019, reducing litigation costs by 30–40%. Botswana and Kenya have both introduced motor vehicle accident fund reforms on similar lines in Sub-Saharan Africa.'
);

-- ── ID 79: Freight Rail Third-Party Access and Transnet Separation ────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    79,
    'Transnet Freight Rail (TFR) operates SA''s 20,800 km freight rail network as a vertically integrated monopoly, combining track infrastructure ownership with train operations. This structure has produced chronically underperforming logistics: coal exports through Richards Bay Coal Terminal fell from 91 million tonnes in 2019 to 54 million tonnes in 2023, costing the fiscus an estimated R50 billion in lost export revenue. The EROT Act (2024) provides the legislative basis for mandated third-party access. A phased implementation is required: Phase 1 targets the coal (TFR North) and iron ore (Sishen–Saldanha) corridors where mining houses have signed volume commitments and are willing to invest in private locomotives. Phase 2 covers the general freight network. Structural separation of Transnet''s infrastructure management from train operations is the medium-term goal.',
    '[
      {"step":1,"title":"Promulgate TER Access Rules under EROT Act Section 34","description":"The Transport Economic Regulator (TER), once constituted, must develop and gazette detailed access rules for freight rail. Rules must cover: capacity allocation methodology (auction vs. administered), access pricing principles (cost-based vs. negotiated), maintenance obligations of third-party operators, and insurance and liability requirements. Consult Transnet, mining export councils (RBCT, Kumba, Exxaro, Anglo American, Glencore), and logistics stakeholders.","timeline":"Q3 2025–Q2 2026","responsible_party":"TER / Department of Transport"},
      {"step":2,"title":"Phase 1 Pilot: Coal and Iron Ore Corridor Access","description":"Implement third-party access on the TFR North coal corridor (Mpumalanga to Richards Bay) and Sishen–Saldanha iron ore corridor under negotiated access agreements with mining operators. Mining houses to provide own locomotives (Transnet-compatible Class 20E or equivalent) under TFR track access charges. Set a 12-month pilot target of 5 million additional tonnes capacity from private operators by end-2026.","timeline":"Q2 2026–Q4 2026 (pilot commencement)","responsible_party":"Transnet / TER / RBCT / SIOC (Sishen Iron Ore Company)"},
      {"step":3,"title":"Transnet Functional Separation: Infrastructure vs. Operations","description":"Require Transnet to establish legally separate business units for (i) infrastructure management (TFR Infrastructure) and (ii) train operations (TFR Operations) with separate profit and loss accounts, cost allocation rules, and regulatory accounts. This functional separation (short of full structural separation) is a precondition for credible access pricing and non-discriminatory access. Set a 24-month target for full functional separation with TER verification.","timeline":"Q3 2025–Q2 2027","responsible_party":"Transnet / Department of Public Enterprises / TER"},
      {"step":4,"title":"Access Pricing Determination: First Regulatory Period","description":"TER issues its first freight rail access pricing determination covering: (i) infrastructure access charge per gross tonne-km; (ii) terminal handling charge at Richards Bay Coal Terminal and Saldanha; (iii) path allocation fees. Charges must allow Transnet to recover efficient infrastructure costs plus a regulated return on the Regulatory Asset Base (RAB), without cross-subsidising Transnet train operations.","timeline":"Q4 2026–Q2 2027","responsible_party":"TER"},
      {"step":5,"title":"General Freight Network Access Programme (Phase 2)","description":"Following the coal and iron ore pilot, extend third-party access to the general freight network (automotive, agri-bulk, chemicals, and containerised cargo). Develop a Network Statement (annual publication by TFR Infrastructure) specifying available capacity, maintenance windows, and access conditions — modelled on European Union Railway Infrastructure Manager Network Statements. Target: first general freight private operator on network by end-2028.","timeline":"2027–2028","responsible_party":"Transnet / TER"},
      {"step":6,"title":"Long-term Structural Separation Assessment","description":"Commission an independent structural review of Transnet by 2028 to assess the case for full statutory separation of TFR Infrastructure (as a regulated public infrastructure company) from TFR Operations (to be concessioned to private operators). Review should consider fiscal implications (Transnet balance sheet, R130 billion debt), employment implications (UNTU/SATAWU), and benchmark against European experience under the EU Railway Directives.","timeline":"2027–2028 (review); decision by 2029","responsible_party":"Department of Public Enterprises / Department of Transport / National Treasury / TER"}
    ]',
    'Phase 1 pilot operational by end-2026; Phase 2 general freight access by end-2028; structural separation decision by 2029',
    'Phase 1: minimal direct cost (regulatory setup R50 million; private operators fund own locomotives); Phase 2: R200–400 million in TER and Transnet systems development; structural separation: R2–5 billion in restructuring costs over 5 years',
    'Economic Regulation of Transport Act No. 6 of 2024 (access rules basis — Section 34); EROT Regulations (Sections 87 and 34); Companies Act implications for Transnet restructuring; Labour Relations Act for any Transnet retrenchments in structural separation; possible amendment to Transnet Concessioning Act',
    'Section 34 of the EROT Act requires the TER to develop access rules but gives significant discretion on access pricing methodology. Draft rules should adopt a cost-based access charge with a published RAB to ensure transparency and prevent Transnet from setting discriminatory prices. The rules should explicitly prohibit Transnet Operations from receiving preferential path allocation over third-party operators. A deemed access provision (access granted unless TER rules otherwise within 30 days) would accelerate practical access.',
    'The political economy is challenging: Transnet unions (UNTU, SATAWU) oppose third-party access as a precursor to privatisation. Framing access as a network competitiveness reform (not privatisation) is essential. Mining industry (Chamber of Mines, RBCT shareholders) strongly supports and has significant political leverage given royalty and export revenue implications. Operation Vulindlela lists freight rail access as a Priority 1 reform. The GNU coalition is broadly supportive — DA and ANC both have incentives to demonstrate logistics improvement.',
    'European Union: EU Railway Directives (2001/14/EC, recast 2012/34/EU) mandated functional and then structural separation of rail infrastructure from operations across member states, producing competitive rail markets in Germany (DB Netz / DB Cargo separation), Netherlands (ProRail / NS), and Sweden (Trafikverket / SJ). Australia: Above-rail competition on the Hunter Valley coal network (ARTC managing track, multiple private train operators including Pacific National and Aurizon) is the closest global precedent to SA''s proposed Phase 1 coal corridor model.'
);

-- ── ID 80: Port Productivity Improvement Programme ────────────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    80,
    'South African ports are among the least productive in the world: Durban''s container dwell time of 8 days (vs. 1 day at Singapore and 4 days at Mombasa) is symptomatic of equipment failures, manual processes, and a monopoly operator (Transnet Port Terminals, TPT) with limited accountability. The Port of Cape Town operates at 45% capacity due to crane breakdowns and labour disputes. This productivity crisis costs the South African economy an estimated R150 billion per year in direct and indirect logistics costs. Operation Vulindlela targets the introduction of private terminal operators at Durban Container Terminal (DCT) Pier 1 and Pier 2 as a structural fix, alongside a 24/7 Port Efficiency Task Team providing interim management support.',
    '[
      {"step":1,"title":"24/7 Port Efficiency Task Team: Immediate Stabilisation","description":"Establish a joint Department of Transport / Transnet / Presidency Port Efficiency Task Team with authority to direct Transnet Port Terminals on equipment maintenance prioritisation, labour scheduling, and gate operating hours. Mandate 24/7 gate operations at DCT Pier 2 and Cape Town Container Terminal. Set a 90-day target of reducing Durban average dwell time from 8 days to 5 days as an interim milestone.","timeline":"Immediate (Q2 2025)","responsible_party":"Presidency (Operation Vulindlela) / Department of Transport / Transnet"},
      {"step":2,"title":"Transnet Port Terminals Concession Process: DCT Pier 1 and Pier 2","description":"Issue a Request for Qualifications (RFQ) for private terminal operators for Durban Container Terminal Pier 1 (3.5M TEU capacity) and Pier 2 (2.5M TEU capacity). Structure as long-term concessions (25–30 years) with private operator responsible for capital investment, equipment, and operations under a revenue-sharing model with Transnet as port authority. Shortlisted operators may include global terminal operators: APM Terminals, DP World, PSA International, and MSC Terminal.","timeline":"RFQ Q3 2025; RFP Q4 2025; preferred bidder Q3 2026; operations transfer Q2 2027","responsible_party":"Transnet / National Treasury PPP Unit / Department of Transport"},
      {"step":3,"title":"Equipment Replacement and Maintenance Programme at Cape Town","description":"Commission an emergency equipment audit at Cape Town Container Terminal and the Port of Cape Town bulk terminals. Procure replacement ship-to-shore cranes and rubber-tyred gantry cranes under an emergency procurement process (PFMA Section 36 deviation if justified). Target: Cape Town Container Terminal operating at 70% capacity utilisation by end-2026.","timeline":"Q2 2025–Q2 2026","responsible_party":"Transnet Port Terminals / Transnet Group Capital"},
      {"step":4,"title":"Port Community System and Digital Integration","description":"Implement a Port Community System (PCS) at Durban and Cape Town ports, integrating SARS Customs (EDI gateway), Transnet''s Navis terminal operating system, shipping lines, freight forwarders, and road transporters. A PCS reduces administrative dwell time by enabling pre-clearance of cargo before vessel arrival. Target: 80% of import containers pre-cleared before vessel berthing by 2027.","timeline":"2025–2027","responsible_party":"Transnet / SARS / ICTS (Port Community System operator)"},
      {"step":5,"title":"Ports Regulator Tariff Methodology Alignment with EROT","description":"Align the Ports Regulator''s tariff determinations (currently under the National Ports Act) with the new EROT Act framework. Ensure Transnet Port Authority''s port dues and terminal tariffs are set on an EROT-compliant cost-reflective basis that enables private terminal concessionaires to earn adequate returns. Publish a 5-year port tariff determination by end-2027.","timeline":"2026–2027","responsible_party":"Ports Regulator / TER / Transnet"},
      {"step":6,"title":"Durban Dig-Out Port: Long-term Capacity Expansion","description":"Advance the planning and environmental approvals for the Durban Dig-Out Port (new greenfield deep-water port south of existing Durban harbour), which will add 10+ million TEU capacity by the mid-2030s. Appoint a transaction advisor to develop the financing model: Development Finance Institution (DBSA, IDC) backed, with private terminal operators. EIA and port development plan to be submitted to DFFE by 2026.","timeline":"Planning 2025–2027; construction 2028–2035","responsible_party":"Transnet / DFFE / DBSA / IDC"},
      {"step":7,"title":"Performance Benchmarking and Annual Port Efficiency Report","description":"Publish an annual SA Port Efficiency Report benchmarking Durban, Cape Town, Richards Bay, Port Elizabeth, and East London against peer ports (Mombasa, Tema, Singapore, Rotterdam) on crane moves per hour, vessel turnaround time, dwell time, and capacity utilisation. Use the report as an accountability mechanism for Transnet Port Terminals and private terminal concessionaires.","timeline":"Annual from 2026","responsible_party":"Ports Regulator / TER / Transnet"}
    ]',
    'Immediate stabilisation 2025; concession awards by 2026; operational improvement to sub-4-day dwell time by 2028; Dig-Out Port completion by 2035',
    'Terminal concession investment: R15–25 billion (private operator funded); emergency equipment: R2–4 billion; Port Community System: R500 million; EROT tariff alignment: minimal; Dig-Out Port: R100+ billion (DFI and private financing)',
    'National Ports Act No. 12 of 2005 (terminal concession framework — Section 56 operating licences); Economic Regulation of Transport Act No. 6 of 2024 (tariff regulation alignment); PFMA and National Treasury PPP Regulations (concession transaction structure); National Environmental Management Act (EIA for Dig-Out Port)',
    'Section 56 of the National Ports Act permits Transnet to grant operating licences to private terminal operators. The concession agreement must specify: minimum performance standards (crane moves per hour, dwell time, throughput targets), investment obligations, employment equity and skills development requirements, and Transnet step-in rights. Any concession with a capital value above R2 billion requires National Treasury PPP Unit approval under PFMA Treasury Regulation 16. The Ports Regulator must approve tariff structures for the concessioned terminals.',
    'Port concessions are an area of significant political sensitivity given Transnet UNTU union membership and past controversies around Gupta-linked logistics contracts. Framing the concession as performance-based operational management (not asset sale) is critical. The Operation Vulindlela backing provides cover. The DA''s governance of the Western Cape means Cape Town improvements have bipartisan support. SARS and SARB both have institutional interests in faster port throughput (customs revenue, foreign exchange earnings).',
    'Malaysia: Klang Container Terminal (Westports) is a long-term private concession that grew from 1 million TEU to 14 million TEU under private management while Klang Port Authority retains infrastructure ownership — a direct model for Durban. Nigeria: Apapa Port concessioned to APM Terminals and others under 25-year BOT agreements in 2006 — mixed results due to road access constraints, but terminal productivity improved. Rotterdam: Port Authority retains public ownership; terminal operations (Hutchison, APM, ECT) are fully private under market conditions.'
);

-- ── ID 81: SANRAL Road Funding Model Reform Post E-Tolls ──────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    81,
    'The discontinuation of Gauteng e-tolls in 2022 resolved a politically explosive dispute but left SANRAL with R23 billion in debt and no substitute revenue stream for the Gauteng Freeway Improvement Project (GFIP). National Treasury committed R23 billion in the 2022 MTBPS to retire SANRAL''s e-toll debt, but the underlying question of how to fund road infrastructure on a sustainable basis — particularly as vehicle fuel efficiency rises and electric vehicles penetrate the fleet — has not been resolved. Two reform paths are available: (i) increased hypothecation of the fuel levy to SANRAL for national road maintenance; or (ii) a distance-based freight charge (heavy vehicle road user charge) that captures wear-and-tear cost from the primary road damage agent.',
    '[
      {"step":1,"title":"Quantify SANRAL Funding Gap and Road Asset Condition","description":"Commission an independent assessment of the national road network asset condition (SANRAL''s 22,000 km network) and the funding gap between current maintenance expenditure and the full asset preservation requirement. The 2022 Road Infrastructure Strategic Framework for SA (RISFSA) provides baseline data. Quantify the additional annual funding required to prevent further network deterioration: estimated R8–12 billion per year.","timeline":"Q2–Q4 2025","responsible_party":"Department of Transport / SANRAL / National Treasury"},
      {"step":2,"title":"Fuel Levy Hypothecation Reform","description":"Develop a proposal to increase the proportion of the general fuel levy (currently R3.93/litre for petrol) hypothecated to road maintenance through the National Roads Fund. Model the fiscal impact of increasing SANRAL''s fuel levy allocation by R1.00/litre (~R8 billion per year), offsetting against general revenue implications. Consult National Treasury, SARS, and the Portfolio Committee on Finance. Present to Cabinet as part of the 2026 Medium Term Budget Policy Statement.","timeline":"Q3 2025–Q2 2026","responsible_party":"National Treasury / Department of Transport / SARS"},
      {"step":3,"title":"Heavy Vehicle Road User Charge Design","description":"Design a distance-based road user charge (RUC) for heavy goods vehicles (gross vehicle mass > 3,500 kg) using GPS or GNSS-based kilometre recording, with a per-km charge differentiated by axle configuration and road type. A heavy vehicle RUC captures road damage costs (pavement damage scales with the fourth power of axle load — the Generalised Fourth Power Law) at source. Commission a technical and legal feasibility study, including benchmarking against New Zealand''s RUC system.","timeline":"Q3 2025–Q2 2026","responsible_party":"Department of Transport / SANRAL / RTMC"},
      {"step":4,"title":"Legislative Framework for Road User Charges","description":"Amend the South African National Roads Agency Limited and National Roads Act (SANRAL Act, No. 7 of 1998) to provide an explicit statutory basis for a distance-based road user charge for heavy vehicles, separate from toll roads. The amendment must define the charge basis, collection mechanism, exemptions, enforcement provisions (integration with RTMC eNaTIS), and allocation of proceeds to the National Roads Fund.","timeline":"Q1 2026–Q4 2026","responsible_party":"Department of Transport / Parliamentary Portfolio Committee on Transport"},
      {"step":5,"title":"E-Toll Debt Retirement and Financial Restructuring","description":"Execute the National Treasury commitment from the 2022 MTBPS to retire SANRAL''s R23 billion e-toll debt. Restructure SANRAL''s balance sheet post-retirement to reduce interest burden and restore investment-grade credit rating (enabling SANRAL to access bond markets for capital expenditure). Set a target of SANRAL achieving a self-funding capital maintenance ratio of 85% from own revenue (tolls + fuel levy allocation + RUC) by 2030.","timeline":"2025–2027 (debt retirement); 2027–2030 (financial restructuring)","responsible_party":"National Treasury / SANRAL"},
      {"step":6,"title":"EV Road Funding Transition Planning","description":"As electric vehicles grow their market share (SA EV target: 50,000 EVs by 2030), model the long-term erosion of fuel levy revenue (estimated 5–8% revenue decline per decade). Develop a policy position paper on transitioning road funding from fuel levies to distance-based charging for all vehicles (not just heavy vehicles) by 2035, drawing on New Zealand and Australia''s EV road user charge pilots.","timeline":"Q4 2025–Q4 2026 (policy paper)","responsible_party":"National Treasury / Department of Transport / SANRAL"}
    ]',
    'Debt retirement 2025–2027; fuel levy hypothecation reform by 2026; heavy vehicle RUC pilot by 2028; long-term EV transition plan by 2030',
    'National Treasury e-toll debt retirement: R23 billion (committed); additional fuel levy hypothecation: R8 billion/year revenue neutral trade-off; heavy vehicle RUC system: R500 million (enforcement technology and RTMC integration)',
    'SANRAL Act No. 7 of 1998 (amendment required for distance-based RUC); South African National Roads Agency Limited Act Amendment Bill; Customs and Excise Act (fuel levy provisions — National Treasury amendments); possibly a new Road User Charges Act if scope extends beyond heavy vehicles',
    'The SANRAL Act amendment for a heavy vehicle RUC should include: (i) a clear definition of qualifying vehicles by GVM and axle category; (ii) a mandatory GPS/GNSS on-board unit specification; (iii) enforcement provisions through RTMC roadblocks and eNaTIS compliance requirements; (iv) an appeal mechanism for disputed charges; and (v) an explicit prohibition on any provincial or municipal surcharge on the national RUC to prevent fragmentation.',
    'E-tolls were politically toxic — any proposal that can be characterised as a new toll system faces intense public resistance. The fuel levy hypothecation approach is the path of least resistance as it is invisible to consumers and administratively simple. A heavy vehicle RUC is more politically defensible than passenger vehicle tolls because it is framed as polluter-pays (heavy vehicles cause 95% of road damage). The trucking industry (SAAFF, RFA) will oppose but may accept if the charge replaces rather than supplements existing costs. The ANC-DA GNU has both parties who opposed e-tolls — a unified position on alternative road funding is achievable.',
    'New Zealand: Distance-based Road User Charges (RUC) for diesel and heavy petrol vehicles since 1978 — one of the world''s longest-running RUC systems; generating NZ$1.2 billion annually; being extended to EVs. Germany: LKW-Maut truck toll on motorways (operated by Toll Collect, now re-nationalised) charges HGVs by distance and emission class; generates EUR 7+ billion annually. UK: HGV Road User Levy Act 2013 introduced a distance-based levy for heavy goods vehicles on UK roads. Australia: National Heavy Vehicle Regulator is developing a similar cost allocation model.'
);

-- ── ID 82: Railway Safety Regulator — Independent Enforcement Capacity ────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    82,
    'The Railway Safety Regulator (RSR), established under the National Railway Safety Regulator Act (No. 16 of 2002), is responsible for certifying railway operators and investigating accidents across SA''s 22,000 km rail network. The RSR is critically under-resourced: only 38 inspectors cover a network operated by Transnet, PRASA, and over 60 private rail operators (including mining and industrial sidings). The 2023 Elandsfontein collision and PRASA derailment record highlight the consequences of inadequate regulatory oversight. RSR needs a staffing expansion, an IT and data management upgrade, and a self-funding model based on operator levies to reduce its dependence on annual parliamentary appropriation.',
    '[
      {"step":1,"title":"RSR Capacity Assessment and Funding Adequacy Review","description":"Commission an independent assessment of RSR''s inspection capacity relative to the risk profile of the rail network. Calculate the minimum inspector-to-network-km ratio required for effective oversight (benchmarking against UK ORR: 1 inspector per 200 km; Australia ONRSR: 1 per 250 km). Current RSR ratio: 1 inspector per 580 km — a tripling of inspector numbers is required. Present findings to the Portfolio Committee on Transport within 6 months.","timeline":"Q2–Q3 2025","responsible_party":"Department of Transport / RSR"},
      {"step":2,"title":"Inspector Recruitment and Training Programme","description":"Recruit 80 additional railway safety inspectors over 3 years (reaching a total of 118+), prioritising civil and electrical engineers, signalling specialists, and rolling stock experts. Develop a structured RSR Inspector Training Programme in partnership with PRASA, Transnet, and international railway safety bodies (UK ORR, Australian ONRSR). Offer competitive salaries benchmarked against Transnet and PRASA technical roles to attract qualified candidates.","timeline":"2025–2028","responsible_party":"RSR / DPSA"},
      {"step":3,"title":"Operator Levy Funding Model","description":"Amend the National Railway Safety Regulator Act to introduce a mandatory annual safety levy on all licensed railway operators, calculated as a proportion of gross revenue or gross tonne-km operated. Model the levy rate to fund RSR''s full operating budget (currently ~R180 million per year from appropriation) within 3 years, reducing RSR''s reliance on annual parliamentary votes and improving budget predictability and independence.","timeline":"Q3 2025–Q2 2026 (legislation); Q1 2027 (first levy collection)","responsible_party":"Department of Transport / RSR / National Treasury"},
      {"step":4,"title":"Safety Information Management System","description":"Implement an integrated Safety Information Management System (SIMS) at the RSR to centralise accident reports, near-miss records, infrastructure condition data, and operator audit findings. Integrate SIMS with Transnet''s Integrated Rail Management System (IRMS) and PRASA''s infrastructure database. The system should enable risk-based inspection scheduling — prioritising high-risk corridors and operators with poor safety records.","timeline":"2025–2027","responsible_party":"RSR / SITA"},
      {"step":5,"title":"Enforcement Capacity: Penalty and Prohibition Powers","description":"Amend the NRSR Act to strengthen RSR enforcement powers: increase the maximum financial penalty from R1 million (current) to R50 million for systemic safety violations; introduce a power to issue immediate operational prohibition notices without court order for imminent safety risks; and require operators to fund remediation costs for accidents caused by non-compliance. Model on UK ORR''s Improvement Notice and Prohibition Notice powers under the Health and Safety at Work Act.","timeline":"Q3 2025–Q2 2026 (legislation)","responsible_party":"Department of Transport / Parliamentary Portfolio Committee on Transport"},
      {"step":6,"title":"Independent Accident Investigation Board","description":"Separate the accident investigation function from the regulatory/certification function within RSR, or establish a standalone Rail Accident Investigation Branch (RAIB) on the model of the UK RAIB and Australian ATSB. An independent investigation body free from any conflict of interest (it does not regulate or certify operators) produces more credible findings and stronger safety learning. If a standalone entity is not immediately feasible, create an independent investigation unit within RSR with a separate reporting line to the Minister.","timeline":"Q4 2025–Q4 2026","responsible_party":"Department of Transport / RSR"}
    ]',
    '3 years for staffing expansion and levy funding model (2025–2028); amended legislation by end-2026; IT system operational 2027',
    'Inspector recruitment: R120 million over 3 years (salaries and training); IT system: R80 million; total annual RSR budget target: R280 million (vs. R180 million current), funded from operator levies',
    'National Railway Safety Regulator Act No. 16 of 2002 (amendment required for levy and enforcement powers); NRSR Amendment Bill; PFMA for RSR as public entity; Labour Relations Act for expanded staff; possible establishment of independent Rail Accident Investigation Branch requiring new legislation or NRSR Act Schedule amendment',
    'The NRSR Act amendment should introduce: (i) a Section 23A levy provision requiring all licensed operators to pay an annual fee calculated by the RSR using a published formula; (ii) a Section 35A immediate prohibition notice power with a 48-hour operator response period; (iii) an increased Section 36 penalty schedule (R50 million maximum); and (iv) an explicit Section 6A mandate for independent accident investigation. Draft legislation should also address RSR''s governance (board composition, appointment process) to ensure independence from Transnet and PRASA political pressure.',
    'RSR reform has low political controversy — it is a technical regulatory capacity issue without strong stakeholder opposition. The main constraint is budget: DPSA may resist salary benchmarking above public sector norms. The case for operator levy funding (self-financing) is strong and has precedent in ICASA and NERSA models. Transnet may prefer weak RSR oversight — careful attention to RSR independence in the amended Act is required. The 2023 Elandsfontein accident and PRASA safety record provide political impetus for action.',
    'UK: Office of Rail and Road (ORR) employs ~180 inspectors for 15,000 km of mainline rail; funded through operator fees under the Railways Act 1993 (as amended). Rail Accident Investigation Branch (RAIB) established 2005 as an independent body under the Railways and Transport Safety Act 2003 — investigations are separate from enforcement. Australia: Office of the National Rail Safety Regulator (ONRSR) established 2013 as a single national regulator replacing state-based regulators; funded through operator accreditation fees; employs ~90 inspectors across the national network.'
);

-- ── ID 83: Minibus Taxi Formalisation and Digital Integration ─────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    83,
    'The minibus taxi industry is SA''s dominant public transport mode, carrying an estimated 15 million passenger trips per day — far exceeding PRASA (100 million/year) or metered taxis. Yet it operates almost entirely informally: fares are set by negotiation, digital payment is negligible, routing is controlled by competing associations (SANTACO, NTA) through violence, and neither operators nor drivers pay income tax on most earnings. The SA Taxi Industry Strategy (2023) targets three structural reforms: (i) universal digital payment integration via a national TaxiLink platform; (ii) GPS tracking and operating licence compliance; and (iii) formal route licensing through operating licences under the National Land Transport Act (NLTA) regulated by provincial operating licence boards (PLAs).',
    '[
      {"step":1,"title":"National Taxi Industry Stakeholder Compact","description":"Convene a structured national dialogue between the Department of Transport, SANTACO (SA National Taxi Council), NTA (National Taxi Alliance), and municipal transport authorities to agree a Taxi Industry Formalisation Compact. The compact should establish shared commitments on: digital payment adoption timelines, GPS tracking installation, route licence compliance, and a violence reduction protocol. The Compact should be endorsed by the Deputy President given the political sensitivity.","timeline":"Q2–Q3 2025","responsible_party":"Department of Transport / Deputy President''s Office"},
      {"step":2,"title":"TaxiLink Digital Payment Platform Roll-out","description":"Accelerate the TaxiLink digital payment platform (already piloted in Johannesburg) to achieve national coverage of 200,000+ registered taxis by end-2027. Platform must support NFC-enabled cards, QR codes, and USSD-based payments to accommodate unbanked passengers. Integrate TaxiLink with PRASA and BRT/IPTN ticketing for seamless intermodal fare payment. Set a target of 60% of taxi trips paid digitally by 2028.","timeline":"2025–2028","responsible_party":"Department of Transport / TaxiLink consortium / SARB (payment system oversight)"},
      {"step":3,"title":"GPS Tracking and Vehicle Safety Compliance","description":"Mandate GPS tracking devices on all licensed minibus taxis under amended NLTA operating licence conditions, phased by province: Gauteng (2026), Western Cape and KwaZulu-Natal (2026–2027), remaining provinces (2027–2028). Tracking data to be accessible to Provincial Licensing Authorities (PLAs) and traffic law enforcement. Simultaneously, run a targeted vehicle roadworthiness enforcement campaign in collaboration with RTMC: target zero-tolerance for taxis without valid operating licences and roadworthy certificates.","timeline":"2025–2028 (phased)","responsible_party":"Department of Transport / PLAs / RTMC"},
      {"step":4,"title":"Route Licensing Rationalisation and Operating Licence Renewal","description":"Undertake a comprehensive Operating Licence Rationalisation (OLR) exercise in all provinces to update route descriptions, eliminate duplicate or conflicting operating licences, and formalise route boundaries. PLAs to issue updated operating licences with GPS-defined route corridors. Existing licence holders given 24-month transition window to update licences; unlicensed operators offered a structured amnesty and fast-track licensing pathway.","timeline":"2025–2027","responsible_party":"PLAs / Department of Transport / provincial transport departments"},
      {"step":5,"title":"Taxi Recapitalisation Programme Phase 2","description":"Expand the Taxi Recapitalisation Programme (TRP) — which subsidises replacement of old and unsafe taxis — to include an EV minibus component (adapted Kia PV5 or BAIC EV or similar) with a differential scrapping allowance for operators who transition to electric vehicles. Integrate TRP with digital payment compliance: operators who adopt TaxiLink receive priority access to TRP subsidies. Target: 15,000 taxis recapitalised per year under TRP Phase 2.","timeline":"2026–2030","responsible_party":"Department of Transport / NTTT / taxi operators / OEMs"},
      {"step":6,"title":"Taxi Revenue and Tax Compliance Integration","description":"Work with SARS to design a simplified tax compliance pathway for taxi operators, using TaxiLink transaction data as a proxy for revenue disclosure. Introduce a presumptive tax regime for taxi operators (per-vehicle annual flat tax) as an intermediary step toward full income tax compliance. Pilot in Gauteng in 2026 before national rollout. Estimated revenue: R2–4 billion per year from an industry with current near-zero formal tax compliance.","timeline":"Q4 2025–Q4 2027","responsible_party":"SARS / Department of Transport / National Treasury"},
      {"step":7,"title":"Violence Reduction and Route Dispute Resolution","description":"Establish a National Taxi Route Dispute Resolution Panel with quasi-judicial powers to adjudicate route boundary disputes between competing taxi associations, replacing the current de facto resolution by violence. Panel to be constituted under NLTA Section 9 powers and supported by GPS route data. Work with SAPS and provincial authorities to prosecute association leaders involved in taxi violence under organised crime provisions of the Prevention of Organised Crime Act (POCA).","timeline":"Q3 2025–Q2 2027","responsible_party":"Department of Transport / SAPS / NPA / provincial transport departments"}
    ]',
    '3–5 years for digital payment and GPS roll-out (2025–2030); route rationalisation by end-2027; long-term full formalisation 10 years',
    'TaxiLink platform: R1.5 billion (development, devices, infrastructure); GPS tracking mandate: R600 million (device costs, partly operator-funded); TRP Phase 2 EV component: R3 billion per year subsidy; route rationalisation: R200 million (PLA systems and administration)',
    'National Land Transport Act No. 5 of 2009 (NLTA — operating licence conditions, PLA powers); NLTA amendment for mandatory GPS tracking condition; National Road Traffic Act (roadworthiness enforcement); National Payment System Act (TaxiLink payment platform oversight); Prevention of Organised Crime Act (violence prosecution); Income Tax Act (presumptive tax regime for operators)',
    'The NLTA amendment for GPS tracking should amend Section 50 (operating licence conditions) to add a mandatory condition requiring an approved tracking device. The amendment should also strengthen PLA enforcement powers: a PLA must be able to suspend an operating licence without a full administrative hearing for a 30-day compliance period when GPS non-compliance is detected. The presumptive tax provision for SARS will require an amendment to the Income Tax Act Schedule 1 or a new Sixth Schedule provision (SA already has Sixth Schedule for small businesses).',
    'The taxi industry is the most politically sensitive transport sector in SA: any formalisation attempt that is perceived as threatening livelihoods triggers violence and political backlash. SANTACO and NTA have historically blocked reforms they perceive as reducing operator income or empowering municipalities at industry expense. The ANC''s broad-based support base includes taxi owners and operators — the ANC has been reluctant to confront the industry directly. Successful formalisation requires genuine industry buy-in through the national compact (Step 1) rather than imposed regulation. The digital payment and GPS tracking reforms offer operators concrete benefits (reduced cash theft, route protection) that may overcome resistance.',
    'Kenya: Matatu industry digitalisation through the Savings and Credit Cooperative (SACCO) model and mandatory GPS tracking (2010 Digital Matatu project in Nairobi) produced a formalised route network, Mpesa-based payments, and Google Maps integration. Nigeria: Lagos BRT integration with informal minibus (danfo) operators through the Lagos Metropolitan Area Transport Authority (LAMATA) provided a partial formalisation model. Colombia: Bogotá''s TransMilenio integration required buying out informal operator route rights and converting operators to shareholders in formal bus companies — a more radical but more complete model.'
);

-- ── ID 84: Integrated Public Transport Networks Scale-up ──────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    84,
    'SA''s Integrated Public Transport Networks (IPTNs) — comprising Bus Rapid Transit (BRT) systems in Johannesburg (Rea Vaya), Cape Town (MyCiTi), Tshwane (A Re Yeng), and partial systems in eThekwini, Buffalo City, and Mangaung — were designed as integrated multi-modal networks but operate at limited scale, serving less than 5% of public transport trips combined. The Public Transport Network Grant (PTNG) has disbursed over R100 billion since 2007 but Phase 2 corridor completions have been delayed by 5–10 years in every city. The IPTN scale-up requires: completing Phase 2 corridors in all metros, achieving taxi recapitalisation integration (converting informal operators to formal IPTN contracts), and transitioning from flat fares to distance-based pricing that enables financial sustainability.',
    '[
      {"step":1,"title":"PTNG Performance Review and Conditional Disbursement Reform","description":"Conduct a comprehensive review of PTNG disbursements and IPTN delivery performance across all six PTNG-receiving metros. Introduce a performance-based disbursement mechanism: future PTNG allocations to be contingent on meeting defined milestones (km of Phase 2 corridor completed, vehicles procured, passengers carried per day). Metros with persistent implementation delays to have portions of their PTNG allocation redirected to high-performing metros or converted to technical assistance funding.","timeline":"Q2–Q3 2025","responsible_party":"Department of Transport / National Treasury / MISA (Municipal Infrastructure Support Agent)"},
      {"step":2,"title":"Phase 2 Corridor Completion: City-by-City Targets","description":"Set binding completion targets for IPTN Phase 2 corridors in each metro: Johannesburg Rea Vaya Phase 1C (Soweto internal corridors) by end-2026; Cape Town MyCiTi Phase 2A (South East corridor to Khayelitsha) by end-2027; Tshwane A Re Yeng Phase 2 by end-2027; eThekwini BRT Phase 1 (full network) by end-2028. Assign a dedicated PTNG implementation manager to each metro with authority to accelerate procurement and resolve contractor delays.","timeline":"2025–2028 (city-specific)","responsible_party":"Department of Transport / metros / PTNG implementation managers"},
      {"step":3,"title":"Taxi Operator Integration: Vehicle Operating Contracts","description":"Design and implement Vehicle Operating Company (VOC) structures that convert existing minibus taxi operators on affected routes into shareholders and employees of formal IPTN bus operating companies. The taxi recapitalisation programme (TRP) provides the financial mechanism: scrapping allowances are paid to operators who surrender taxi operating licences in exchange for VOC shares. Model on Johannesburg Rea Vaya Phase 1A VOC (Piotrans/Itumele bus companies) which successfully integrated ~400 taxi operators.","timeline":"2025–2029 (city-specific)","responsible_party":"Metros / Department of Transport / SANTACO / NTA"},
      {"step":4,"title":"Distance-Based Fare System Design and Implementation","description":"Transition all IPTN systems from flat fares to distance-based (or zone-based) fare systems to enable cost recovery, cross-subsidisation of long-distance trips, and integration with other modes. Commission a national IPTN Fare Reform Study to model the impact of fare restructuring on ridership (particularly low-income commuters) and system financial sustainability. Introduce an IPTN social tariff (means-tested subsidy card) to protect affordability for the lowest-income quintiles.","timeline":"Q3 2025–Q4 2026 (study and design); 2027–2028 (implementation)","responsible_party":"Department of Transport / metros / National Treasury"},
      {"step":5,"title":"Interoperable Ticketing Platform Across All IPTNs","description":"Implement a national interoperable IPTN ticketing platform enabling a single smart card or app to be used across Rea Vaya, MyCiTi, A Re Yeng, Gautrain, and PRASA Metrorail. Award a national contract for the ticketing platform (back-office) while allowing cities to maintain their own front-end (card/app). Integrate with TaxiLink for the minibus taxi leg of multi-modal journeys. Target: interoperability in all six PTNG metros by end-2028.","timeline":"2025–2028","responsible_party":"Department of Transport / metros / SANRAL / PRASA"},
      {"step":6,"title":"PTNG Grant Reform: Long-Term Operational Subsidy Framework","description":"Reform the PTNG to separate capital grants (for infrastructure: depots, stations, BRT lanes) from operational subsidies (for bus services). The current PTNG conflates both, creating perverse incentives for metros to prioritise capital spending over operational viability. A dedicated IPTN Operational Subsidy Grant should be calibrated on passenger-km carried at a benchmark cost-efficiency rate, incentivising ridership growth and cost control.","timeline":"2026–2027 (framework); 2028 (implementation)","responsible_party":"National Treasury / Department of Transport"},
      {"step":7,"title":"IPTN Monitoring and Annual Performance Reporting","description":"Establish an annual IPTN Performance Report published by the Department of Transport, covering: passengers per day per system, cost per passenger-km, farebox recovery ratio, route-km completed vs. planned, and taxi integration progress. Use the report to hold metros accountable and inform PTNG allocation decisions. Report to be tabled in the Portfolio Committee on Transport annually.","timeline":"Annual from 2026","responsible_party":"Department of Transport"}
    ]',
    '5–8 years for Phase 2 completions and taxi integration (2025–2032); interoperable ticketing by 2028; financial sustainability targets by 2030',
    'PTNG disbursements: R15–18 billion per year (existing); additional IPTN operational subsidy grant: R3–5 billion per year; distance-based fare study: R30 million; interoperable ticketing platform: R400 million',
    'National Land Transport Act No. 5 of 2009 (IPTN framework, PTNG conditions, PLA operating licences); Division of Revenue Act (annual PTNG allocation conditions); possible NLTA amendment for national interoperable ticketing mandate; PRASA integration may require amendment to Legal Succession to SATS Act',
    'The DOURA (Division of Revenue Act) conditions for PTNG disbursement are the primary accountability lever and can be amended annually through the budget process without requiring new legislation. NLTA Section 41 provides for integrated public transport networks as municipal responsibility. A NLTA amendment may be needed to mandate interoperable ticketing standards nationally, as the current Act leaves ticketing to municipal discretion. Draft amendment should include a Section 7A national ticketing interoperability standard to be set by the Minister by notice in the Gazette.',
    'IPTN reform is within ANC/DA municipal competence and has strong urban constituency support. The taxi integration component is politically sensitive (same dynamics as ID 83). The PTNG performance conditionality reform may face resistance from metros that have become accustomed to unconditional infrastructure grant flows. National Treasury strongly supports performance conditions in grants — this is an area of broad political consensus. The ANC''s urban base (Soweto, Khayelitsha) is directly served by Rea Vaya and MyCiTi and benefits from expansion.',
    'Brazil: TransMilenio (Bogotá) and MOVE (Belo Horizonte) BRT systems achieved farebox recovery ratios of 70–80% through distance-based fares and VOC operator structures — considered the gold standard for BRT financial sustainability. Colombia: TransMilenio Phase 3 integrated motorcycle-taxi operators through a VOC model analogous to SA''s taxi integration approach. China: Guangzhou BRT (world''s highest-capacity BRT corridor, 800,000 passengers/day) achieved this through dedicated right-of-way, level boarding, and integrated ticketing — a scale model for Johannesburg''s Rea Vaya.'
);

-- ── ID 85: Merchant Shipping and Maritime Industry Development ────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    85,
    'SA''s 3,900 km coastline straddles two of the world''s most important maritime trade routes — the Cape of Good Hope route (Asia–Europe round-Africa passage) and the Indian Ocean lanes to Asia — yet SA has no meaningful merchant shipping industry, no significant ship repair capacity outside a small Durban dry dock, and a maritime sector contribution to GDP of less than 0.5%. The Saldanha Bay IDZ (industrial development zone) and Richards Bay Maritime Zone offer designated locations for maritime industrial development. A Maritime Industry Development Plan (MIDP), building on the South African Maritime Safety Authority (SAMSA) mandate and the Operation Phakisa Ocean Economy initiative, could develop ship repair, offshore oil/gas support services, and aquaculture, targeting a maritime GDP contribution of 5% by 2033.',
    '[
      {"step":1,"title":"Maritime Industry Development Plan: Publication and Coordination","description":"The Department of Transport (maritime division) and SAMSA, working with the Department of Trade, Industry and Competition (DTIC), must publish a comprehensive Maritime Industry Development Plan (MIDP) that consolidates existing Operation Phakisa Ocean Economy commitments with a realistic, costed implementation roadmap. The MIDP should identify the five highest-value maritime sub-sectors for SA: ship repair/dry docking, offshore oil/gas services, marine aquaculture, maritime logistics services, and ocean data/research. Assign a Cabinet-level champion (Deputy Minister level) for maritime development.","timeline":"Q2–Q4 2025","responsible_party":"Department of Transport / DTIC / SAMSA / Operation Phakisa"},
      {"step":2,"title":"Saldanha Bay IDZ: Offshore and Ship Repair Investment Cluster","description":"Target Saldanha Bay IDZ as the primary hub for ship repair and offshore oil/gas support services, leveraging proximity to the Cape shipping route and the existing iron ore export terminal infrastructure. Develop a targeted investment incentive package: IDZ manufacturing incentive (Section 12I of Income Tax Act), customs duty relief on imported marine equipment, and a DTIC equity co-investment fund for qualifying maritime firms. Target R5 billion in new private investment in Saldanha Bay maritime cluster by 2030.","timeline":"2025–2028","responsible_party":"DTIC / Saldanha Bay IDZ / IDC"},
      {"step":3,"title":"SA Ship Register and Flag State Administration Reform","description":"SA''s ship register (administered by SAMSA) carries fewer than 50 vessels — one of the smallest registers relative to GDP among maritime nations. Reform the SA Ships Registration Act to create a second register (an international ship register) offering competitive flag state conditions: lower tonnage taxes, relaxed manning requirements for international voyages, and streamlined SAMSA certification. Target: 200 vessels on the SA register by 2030, generating R500 million per year in tonnage tax and SAMSA fee revenue.","timeline":"Q3 2025–Q2 2027","responsible_party":"SAMSA / Department of Transport"},
      {"step":4,"title":"Maritime Skills Development and Seafarer Training","description":"Address SA''s severe shortage of qualified seafarers (SAMSA estimates a shortfall of 5,000 officers) through an expanded Maritime Skills Development Programme. Partner with the SA Maritime Training Authority (SAMTRA), Nelson Mandela University (maritime centre), and Mangosuthu University of Technology to expand STCW (International Convention on Standards of Training, Certification and Watchkeeping) certified officer training to 1,000 graduates per year by 2028. Establish a maritime bursary programme funded through SAMSA vessel levies.","timeline":"2025–2030","responsible_party":"SAMSA / DHET / maritime training institutions"},
      {"step":5,"title":"Cabotage Policy for Coastal Shipping","description":"Introduce a cabotage policy for coastal shipping (SA-flagged vessels carrying cargo between SA ports) under the Merchant Shipping Act to develop domestic maritime logistics as a complement to road and rail. Consult shippers, logistics operators, and international shipping lines on the cabotage design. Model on Norway''s NOR register (international register with domestic cabotage protection) and Brazil''s CADE-approved cabotage policy that grew coastal shipping from 8% to 14% of freight modal share.","timeline":"Q3 2025–Q2 2026 (policy paper); Q3 2026–Q4 2027 (legislation)","responsible_party":"Department of Transport / SAMSA / DTIC / National Treasury"},
      {"step":6,"title":"Richards Bay Maritime Zone: Oil, Gas, and Offshore Services","description":"Develop Richards Bay as SA''s specialist offshore oil/gas support services hub, serving the Durban Deep offshore gas fields (TotalEnergies and Impact Oil blocks) and Mozambican LNG development (Coral FLNG, Rovuma Basin). Establish an offshore services supply base at Richards Bay with TRANSNET-operated quayside facilities and an IDZ incentive zone. Target: 10 offshore support vessel (OSV) operators basing vessels in Richards Bay by 2030.","timeline":"2025–2030","responsible_party":"Richards Bay IDZ / Transnet / DTIC / PASA (Petroleum Agency SA)"},
      {"step":7,"title":"Marine Aquaculture Development: Blue Economy Component","description":"Develop marine aquaculture as a distinct MIDP sub-sector, building on existing abalone farming at Hermanus and Saldanha Bay. Fast-track aquaculture permits through DFFE (Department of Forestry, Fisheries and the Environment) using the Aquaculture Development and Enhancement Programme (ADEP). Target: 50,000 tonnes per year of marine aquaculture production by 2030 (from a current base of 5,000 tonnes), generating R2 billion per year in export revenue.","timeline":"2025–2030","responsible_party":"DFFE / DTIC / Aquaculture SA / IDC"}
    ]',
    '8–10 years for substantive maritime industry development (2025–2033); Saldanha Bay investment cluster visible by 2028; second ship register operational 2027',
    'MIDP development: R50 million (consultants, coordination); IDZ incentives: R1.5 billion over 5 years (tax expenditure); ship register reform: R30 million (SAMSA); maritime training: R500 million over 5 years; offshore services hub (Richards Bay): R2 billion (Transnet and IDC infrastructure); aquaculture ADEP: R800 million over 5 years',
    'SA Ships Registration Act No. 58 of 1998 (amendment for second international register); Merchant Shipping Act No. 57 of 1951 (cabotage provisions); Marine Living Resources Act No. 18 of 1998 (aquaculture permit reform); IDZ Act and SEZ Act (Saldanha Bay and Richards Bay zone expansion); Income Tax Act (Section 12I manufacturing incentive for maritime); Petroleum Resources Development Act (offshore block licensing for PASA)',
    'The second international ship register requires an amendment to the SA Ships Registration Act to create a Part II register (international ships) with separate manning, tonnage tax, and certification conditions from the domestic Part I register. The Merchant Shipping Act cabotage provision should include: (i) a phase-in period of 5 years to allow SA flag build-up; (ii) a waiver mechanism for routes where no SA-flagged vessel is available; and (iii) an explicit link to South African seafarer employment quotas. Aquaculture permit reform should amend MLRA Section 18 to introduce a streamlined Long-term Aquaculture Authorisation replacing the current annual permit cycle.',
    'Maritime industrial policy is low-political-salience in SA, which paradoxically makes it easier to reform — there is no powerful incumbent lobby blocking the SA ship register second tier or the Richards Bay offshore hub. Operation Phakisa provides an existing political mandate (signed off at Cabinet level in 2014). COSATU and maritime unions (SATAWU maritime branch) will support job creation in ship repair and seafarer training. The Mozambican LNG development and increased Cape route shipping (driven by Red Sea conflict diversions from 2024) provide favourable external conditions for SA maritime investment. Environmental groups may contest some offshore oil/gas support facility permitting.',
    'Norway: NOR (Norwegian International Ship Register) since 1987 created a competitive international register alongside the domestic NIS register, attracting 500+ vessels and generating significant tonnage tax and maritime cluster spillovers. Brazil: Cabotage policy combined with BNDES financing for domestic vessel construction grew coastal shipping from near-zero to 14% of freight modal share within a decade. Australia: Australian International Shipping Register (AISR, 2012) attempted similar ship register reform with mixed results — offering both a positive model and cautionary lessons on register competitiveness criteria. UAE (Dubai): Drydocks World Jebel Ali is the global benchmark for a successful ship repair hub built around a strategic shipping chokepoint — directly analogous to SA''s Cape route positioning.'
);

COMMIT;
